// FCMGT (zero) vector .4S — V_d = (V_n > 0) ? all-ones : 0
#define VFCMGTZ_S4(n, d) WORD $(0x4EA0C800 | ((n) << 5) | (d))
// FCMLT (zero) vector .4S — V_d = (V_n < 0) ? all-ones : 0
