// loop is then identical to SGD with that effective LR:
//   effective = grad + weightDecay*params
//   momentum = momentumFactor*momentum + effective
//   output = params - effectiveLr * momentum
TEXT ·LarsStepFloat32NEONAsm(SB), NOSPLIT, $0-56
    MOVD params+0(FP), R0
    MOVD grad+8(FP), R1
    MOVD momentum+16(FP), R2
    MOVD output+24(FP), R3
    MOVD n+32(FP), R4

    MOVD momentumFactor+44(FP), R6
    VMOV R6, V17.S[0]
    VDUP V17.S[0], V17.S4
    MOVD weightDecay+48(FP), R6
    VMOV R6, V18.S[0]
    VDUP V18.S[0], V18.S4
    MOVD effectiveLr+52(FP), R6
    VMOV R6, V16.S[0]
    VDUP V16.S[0], V16.S4

lars_loop4:
    CMP  $4, R4
    BLT  lars_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VLD1 (R2), [V2.S4]
    // effective = grad + weightDecay*params
    VFMLA_S4(0, 18, 1)
    // momentum = momentumFactor*momentum + effective (FMA to match Go scalar)
    VFMLA_S4(2, 17, 1)
    // out = params - effectiveLr*momentum (FMA with -lr)
    VFNEG_S4(16, 26)
    VFMLA_S4(1, 26, 0)
    VST1 [V1.S4], (R2)
    VST1 [V0.S4], (R3)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    ADD  $16, R3
    SUB  $4, R4
    B    lars_loop4

lars_done:
    RET

// func HebbianStepRowFloat32NEONAsm(
//     weights, pre, output *float32,
//     n int,
//     decayFactor, lrPost float32,
// )
//
// output = weights * decayFactor + lrPost * pre
TEXT ·HebbianStepRowFloat32NEONAsm(SB), NOSPLIT, $0-40
    MOVD weights+0(FP), R0
    MOVD pre+8(FP), R1
    MOVD output+16(FP), R2
    MOVD n+24(FP), R4
    FMOVS decayFactor+32(FP), F16
    VDUP V16.S[0], V16.S4
    FMOVS lrPost+36(FP), F17
    VDUP V17.S[0], V17.S4

hebbian_loop4:
    CMP  $4, R4
    BLT  hebbian_done
    VLD1 (R0), [V0.S4]
    VLD1 (R1), [V1.S4]
    VFMUL_S4(16, 0, 2)
    VFMLA_S4(1, 17, 2)
    VST1 [V2.S4], (R2)
    ADD  $16, R0
    ADD  $16, R1
    ADD  $16, R2
    SUB  $4, R4
    B    hebbian_loop4

hebbian_done:
    RET
